var requestCount int
func rateLimitHandler(next echo.HandlerFunc) echo.HandlerFunc {
    return func(c echo.Context) error {
        requestCount++
        if requestCount > 100 {
            return echo.NewHTTPError(429)
        }
        return next(c)
    }
}

e.GET("/static/*", func(c echo.Context) error {
    path := c.Param("*")
    data, err := os.ReadFile("assets/" + path)
    if err != nil {
        return echo.NewHTTPError(404)
    }
    return c.Blob(200, "application/octet-stream", data)
})

